1	// TrayIcon.cpp: implementation of the CSystemTray class.
2	//
3	// NON-MFC VERSION
4	//
5	// This class is a light wrapper around the windows system tray stuff. It
6	// adds an icon to the system tray with the specified ToolTip text and
7	// callback notification value, which is sent back to the Parent window.
8	//
9	// Updated: 21 Sep 2000 - Added GetDoWndAnimation - animation only occurs if the
10	// system
11	//                        settings allow it (Matthew Ellis). Updated the
12	//                        GetTrayWndRect function to include more fallback logic
13	//                        (Matthew Ellis)
14	//
15	// Updated: 4 Aug 2003 - Fixed bug that was stopping icon from being recreated
16	// when
17	//                       Explorer crashed
18	//                       Fixed resource leak in SetIcon
19	//						 Animate() now checks for empty
20	// icon list - Anton Treskunov 						 Added
21	// the virutal CustomizeMenu() method - Anton Treskunov
22	//
23	// 2007-11-14 GONG Chen - made modifications to enable Unicode support.
24	//
25	// Written by Chris Maunder (cmaunder@mail.com)
26	// Copyright (c) 1999-2003.
27	//
28	/////////////////////////////////////////////////////////////////////////////
29	
30	#include "stdafx.h"
31	#include "SystemTraySDK.h"
32	
