34	#undef THIS_FILE
35	static char THIS_FILE[] = __FILE__;
36	#define new DEBUG_NEW
37	#endif
38	
39	#ifndef ASSERT
40	#include <assert.h>
41	#define ASSERT assert
42	#endif
43	
44	#ifndef _countof
45	#define _countof(x) (sizeof(x) / sizeof(x[0]))
46	#endif
47	
48	// 2007-11-14 GONG
