50	// #error "Unicode not yet suported"
51	// #endif
52	
53	#define TRAYICON_CLASS _T("TrayIconClass")
54	
55	// The option here is to maintain a list of all TrayIcon windows,
56	// and iterate through them, instead of only allowing a single
57	// TrayIcon per application
58	CSystemTray* CSystemTray::m_pThis = NULL;
59	
60	const UINT_PTR CSystemTray::m_nTimerID = 4567;
61	UINT CSystemTray::m_nMaxTooltipLength = 64;  // This may change...
62	const UINT CSystemTray::m_nTaskbarCreatedMsg =
63	    ::RegisterWindowMessage(_T("TaskbarCreated"));
