92	void CSystemTray::Initialise() {
93	  // If maintaining a list of all TrayIcon windows (instead of
94	  // only allowing a single TrayIcon per application) then add
95	  // this TrayIcon to the list
96	  m_pThis = this;
97	
98	  memset(&m_tnd, 0, sizeof(m_tnd));
99	  m_bEnabled = FALSE;
100	  m_bHidden = TRUE;
101	  m_bRemoved = TRUE;
102	
103	  m_DefaultMenuItemID = 0;
104	  m_DefaultMenuItemByPos = TRUE;
105	
106	  m_bShowIconPending = FALSE;
107	
108	  m_uIDTimer = 0;
109	  m_hSavedIcon = NULL;
110	
111	  m_hTargetWnd = NULL;
112	  m_uCreationFlags = 0;
113	
114	#ifdef SYSTEMTRAY_USEW2K
115	  OSVERSIONINFOEX osInfo = {0};
116	  osInfo.dwOSVersionInfoSize = sizeof(osInfo);
117	  osInfo.dwMajorVersion = 5;
118	  osInfo.dwPlatformId = VER_PLATFORM_WIN32_NT;
119	  DWORDLONG conditionMask = 0;
120	  conditionMask =
121	      VerSetConditionMask(conditionMask, VER_MAJORVERSION, VER_GREATER_EQUAL);
122	  conditionMask = VerSetConditionMask(conditionMask, VER_PLATFORMID, VER_EQUAL);
123	  m_bWin2K = VerifyVersionInfo(&osInfo, VER_MAJORVERSION | VER_PLATFORMID,
124	                               conditionMask);
125	#else
126	  m_bWin2K = FALSE;
127	#endif
128	}
