149	
150	BOOL CSystemTray::Create(HINSTANCE hInst,
151	                         HWND hParent,
152	                         UINT uCallbackMessage,
153	                         LPCTSTR szToolTip,
154	                         HICON icon,
155	                         UINT uID,
156	                         BOOL bHidden /*=FALSE*/,
157	                         LPCTSTR szBalloonTip /*=NULL*/,
158	                         LPCTSTR szBalloonTitle /*=NULL*/,
159	                         DWORD dwBalloonIcon /*=NIIF_NONE*/,
160	                         UINT uBalloonTimeout /*=10*/) {
161	#ifdef _WIN32_WCE
162	  m_bEnabled = TRUE;
163	#else
164	  // this is only for Windows 95 (or higher)
165	  OSVERSIONINFOEXW osInfo = {0};
166	  osInfo.dwOSVersionInfoSize = sizeof(osInfo);
167	  osInfo.dwMajorVersion = 4;
168	  DWORDLONG conditionMask = 0;
169	  conditionMask =
170	      VerSetConditionMask(conditionMask, VER_MAJORVERSION, VER_GREATER_EQUAL);
171	  m_bEnabled = VerifyVersionInfoW(&osInfo, VER_MAJORVERSION, conditionMask);
172	  if (!m_bEnabled) {
173	    ASSERT(FALSE);
174	    return FALSE;
175	  }
176	#endif
177	
178	  m_nMaxTooltipLength = _countof(m_tnd.szTip);
179	
180	  // Make sure we avoid conflict with other messages
181	  ASSERT(uCallbackMessage >= WM_APP);
182	
183	  // Tray only supports tooltip text up to m_nMaxTooltipLength) characters
184	  ASSERT(_tcslen(szToolTip) <= m_nMaxTooltipLength);
185	
186	  m_hInstance = hInst;
187	
188	  RegisterClass(hInst);
189	
190	  // Create an invisible window
191	  m_hWnd = ::CreateWindow(TRAYICON_CLASS, _T(""), WS_POPUP, CW_USEDEFAULT,
192	                          CW_USEDEFAULT, CW_USEDEFAULT, CW_USEDEFAULT, NULL, 0,
193	                          hInst, 0);
194	
195	  // load up the NOTIFYICONDATA structure
196	  // m_tnd.cbSize = sizeof(NOTIFYICONDATA);
197	  m_tnd.cbSize =
198	      NOTIFYICONDATA_V2_SIZE;  // 2012-01-05 GONG Chen, XP compatibility
199	  m_tnd.hWnd = (hParent) ? hParent : m_hWnd;
200	  m_tnd.uID = uID;
201	  m_tnd.hIcon = icon;
202	  m_tnd.uFlags = NIF_MESSAGE | NIF_ICON | NIF_TIP;
203	  m_tnd.uCallbackMessage = uCallbackMessage;
204	
205	  // 2007-11-14 GONG
206	  _tcsncpy_s(m_tnd.szTip, _countof(m_tnd.szTip), szToolTip,
207	             m_nMaxTooltipLength);
208	
209	#ifdef SYSTEMTRAY_USEW2K
210	  if (m_bWin2K && szBalloonTip) {
211	#if _MSC_VER < 0x1000
212	    // The balloon tooltip text can be up to 255 chars long.
213	    //        ASSERT(AfxIsValidString(szBalloonTip));
214	    ASSERT(lstrlen(szBalloonTip) < 256);
215	#endif
216	
217	    // The balloon title text can be up to 63 chars long.
218	    if (szBalloonTitle) {
219	      //            ASSERT(AfxIsValidString(szBalloonTitle));
220	      ASSERT(lstrlen(szBalloonTitle) < 64);
221	    }
222	
223	    // dwBalloonIcon must be valid.
224	    ASSERT(NIIF_NONE == dwBalloonIcon || NIIF_INFO == dwBalloonIcon ||
225	           NIIF_WARNING == dwBalloonIcon || NIIF_ERROR == dwBalloonIcon);
226	
227	    // The timeout must be between 10 and 30 seconds.
228	    ASSERT(uBalloonTimeout >= 10 && uBalloonTimeout <= 30);
229	
230	    m_tnd.uFlags |= NIF_INFO;
231	
232	    _tcsncpy_s(m_tnd.szInfo, _countof(m_tnd.szInfo), szBalloonTip, 255);
233	    if (szBalloonTitle)
234	      _tcsncpy_s(m_tnd.szInfoTitle, _countof(m_tnd.szInfoTitle), szBalloonTitle,
235	                 63);
236	    else
237	      m_tnd.szInfoTitle[0] = _T('\0');
238	    m_tnd.uTimeout = uBalloonTimeout * 1000;  // convert time to ms
239	    m_tnd.dwInfoFlags = dwBalloonIcon;
240	  }
241	#endif
242	
243	  m_bHidden = bHidden;
244	  m_hTargetWnd = m_tnd.hWnd;
245	
246	#ifdef SYSTEMTRAY_USEW2K
247	  if (m_bWin2K && m_bHidden) {
248	    m_tnd.uFlags = NIF_STATE;
249	    m_tnd.dwState = NIS_HIDDEN;
250	    m_tnd.dwStateMask = NIS_HIDDEN;
251	  }
252	#endif
253	
254	  m_uCreationFlags =
255	      m_tnd.uFlags;  // Store in case we need to recreate in OnTaskBarCreate
256	
257	  BOOL bResult = TRUE;
258	  if (!m_bHidden || m_bWin2K) {
259	    bResult = Shell_NotifyIcon(NIM_ADD, &m_tnd);
260	    m_bShowIconPending = m_bHidden = m_bRemoved = !bResult;
261	  }
262	
263	#ifdef SYSTEMTRAY_USEW2K
264	  if (m_bWin2K && szBalloonTip) {
265	    // Zero out the balloon text string so that later operations won't redisplay
266	    // the balloon.
267	    m_tnd.szInfo[0] = _T('\0');
268	  }
269	#endif
270	
271	  return bResult;
272	}
