295	BOOL CSystemTray::AddIcon() {
296	  if (!m_bRemoved)
297	    RemoveIcon();
298	
299	  if (m_bEnabled) {
300	    m_tnd.uFlags = NIF_MESSAGE | NIF_ICON | NIF_TIP;
301	    if (!Shell_NotifyIcon(NIM_ADD, &m_tnd))
302	      m_bShowIconPending = TRUE;
303	    else
304	      m_bRemoved = m_bHidden = FALSE;
305	  }
306	  return (m_bRemoved == FALSE);
307	}
308	
309	BOOL CSystemTray::RemoveIcon() {
310	  m_bShowIconPending = FALSE;
311	
312	  if (!m_bEnabled || m_bRemoved)
313	    return TRUE;
314	
315	  m_tnd.uFlags = 0;
316	  if (Shell_NotifyIcon(NIM_DELETE, &m_tnd))
317	    m_bRemoved = m_bHidden = TRUE;
318	
319	  return (m_bRemoved == TRUE);
320	}
321	
322	BOOL CSystemTray::HideIcon() {
323	  if (!m_bEnabled || m_bRemoved || m_bHidden)
324	    return TRUE;
325	
326	#ifdef SYSTEMTRAY_USEW2K
327	  if (m_bWin2K) {
328	    m_tnd.uFlags = NIF_STATE;
329	    m_tnd.dwState = NIS_HIDDEN;
330	    m_tnd.dwStateMask = NIS_HIDDEN;
331	
332	    m_bHidden = Shell_NotifyIcon(NIM_MODIFY, &m_tnd);
333	  } else
334	#endif
335	    RemoveIcon();
336	
337	  return (m_bHidden == TRUE);
338	}
339	
340	BOOL CSystemTray::ShowIcon() {
341	  if (m_bRemoved)
342	    return AddIcon();
343	
344	  if (!m_bHidden)
345	    return TRUE;
346	
347	#ifdef SYSTEMTRAY_USEW2K
348	  if (m_bWin2K) {
349	    m_tnd.uFlags = NIF_STATE;
350	    m_tnd.dwState = 0;
351	    m_tnd.dwStateMask = NIS_HIDDEN;
352	    Shell_NotifyIcon(NIM_MODIFY, &m_tnd);
353	  } else
354	#endif
355	    AddIcon();
356	
357	  return (m_bHidden == FALSE);
358	}
