409	BOOL CSystemTray::SetIconList(UINT uFirstIconID, UINT uLastIconID) {
410	  if (uFirstIconID > uLastIconID)
411	    return FALSE;
412	
413	  UINT uIconArraySize = uLastIconID - uFirstIconID + 1;
414	
415	  m_IconList.clear();
416	  try {
417	    for (UINT i = uFirstIconID; i <= uLastIconID; i++)
418	      m_IconList.push_back(::LoadIcon(m_hInstance, MAKEINTRESOURCE(i)));
419	  } catch (...) {
420	    m_IconList.clear();
421	    return FALSE;
422	  }
423	
424	  return TRUE;
425	}
