428	  m_IconList.clear();
429	
430	  try {
431	    for (UINT i = 0; i <= nNumIcons; i++)
432	      m_IconList.push_back(pHIconList[i]);
433	  } catch (...) {
434	    m_IconList.clear();
435	    return FALSE;
436	  }
437	
