441	BOOL CSystemTray::Animate(UINT nDelayMilliSeconds, int nNumSeconds /*=-1*/) {
442	  if (m_IconList.empty())
443	    return FALSE;
444	
445	  StopAnimation();
446	
447	  m_nCurrentIcon = 0;
448	  time(&m_StartTime);
449	  m_nAnimationPeriod = nNumSeconds;
450	  m_hSavedIcon = GetIcon();
451	
452	  // Setup a timer for the animation
453	  m_uIDTimer = ::SetTimer(m_hWnd, m_nTimerID, nDelayMilliSeconds, NULL);
454	  return (m_uIDTimer != 0);
455	}
