457	BOOL CSystemTray::StepAnimation() {
458	  if (!m_IconList.size())
459	    return FALSE;
460	
461	  m_nCurrentIcon++;
462	  if (m_nCurrentIcon >= (int)m_IconList.size())
463	    m_nCurrentIcon = 0;
464	
465	  return SetIcon(m_IconList[m_nCurrentIcon]);
466	}
467	
468	BOOL CSystemTray::StopAnimation() {
469	  BOOL bResult = FALSE;
470	
471	  if (m_uIDTimer)
472	    bResult = ::KillTimer(m_hWnd, m_uIDTimer);
473	  m_uIDTimer = 0;
474	
475	  if (m_hSavedIcon)
476	    SetIcon(m_hSavedIcon);
477	  m_hSavedIcon = NULL;
478	
479	  return bResult;
480	}
