520	  //    strBuffer[0] = _T('\0');
521	  //    MultiByteToWideChar(CP_ACP, 0, m_tnd.szTip, -1, strBuffer,
522	  //    m_nMaxTooltipLength, NULL, NULL);
523	  // #else
524	  //    strncpy(strBuffer, m_tnd.szTip, m_nMaxTooltipLength-1);
525	  // #endif
