534	// Function:    ShowBalloon
535	//
536	// Description:
537	//  Shows a balloon tooltip over the tray icon.
538	//
539	// Input:
540	//  szText: [in] Text for the balloon tooltip.
541	//  szTitle: [in] Title for the balloon.  This text is shown in bold above
542	//           the tooltip text (szText).  Pass "" if you don't want a title.
543	//  dwIcon: [in] Specifies an icon to appear in the balloon.  Legal values are:
544	//                 NIIF_NONE: No icon
545	//                 NIIF_INFO: Information
546	//                 NIIF_WARNING: Exclamation
547	//                 NIIF_ERROR: Critical error (red circle with X)
548	//  uTimeout: [in] Number of seconds for the balloon to remain visible.  Can
549	//            be between 10 and 30 inclusive.
550	//
551	// Returns:
552	//  TRUE if successful, FALSE if not.
553	//
554	//////////////////////////////////////////////////////////////////////////
555	// Added by Michael Dunn, November 1999
556	//////////////////////////////////////////////////////////////////////////
557	
558	BOOL CSystemTray::ShowBalloon(LPCTSTR szText,
559	                              LPCTSTR szTitle /*=NULL*/,
560	                              DWORD dwIcon /*=NIIF_NONE*/,
561	                              UINT uTimeout /*=10*/) {
562	#ifndef SYSTEMTRAY_USEW2K
563	  return FALSE;
564	#else
565	  // Bail out if we're not on Win 2K.
566	  if (!m_bWin2K)
567	    return FALSE;
568	
569	  // Verify input parameters.
570	
571	  // The balloon tooltip text can be up to 255 chars long.
572	  //    ASSERT(AfxIsValidString(szText));
573	  ASSERT(lstrlen(szText) < 256);
574	
575	  // The balloon title text can be up to 63 chars long.
576	  if (szTitle) {
577	    //        ASSERT(AfxIsValidString( szTitle));
578	    ASSERT(lstrlen(szTitle) < 64);
579	  }
580	
581	  // dwBalloonIcon must be valid.
582	  ASSERT(NIIF_NONE == dwIcon || NIIF_INFO == dwIcon || NIIF_WARNING == dwIcon ||
583	         NIIF_ERROR == dwIcon);
584	
585	  // The timeout must be between 10 and 30 seconds.
586	  ASSERT(uTimeout >= 10 && uTimeout <= 30);
587	
588	  m_tnd.uFlags = NIF_INFO;
589	  _tcsncpy_s(m_tnd.szInfo, _countof(m_tnd.szInfo), szText, 256);
590	  if (szTitle)
591	    _tcsncpy_s(m_tnd.szInfoTitle, _countof(m_tnd.szInfoTitle), szTitle, 64);
592	  else
593	    m_tnd.szInfoTitle[0] = _T('\0');
594	  m_tnd.dwInfoFlags = dwIcon;
595	  m_tnd.uTimeout = uTimeout * 1000;  // convert time to ms
596	
597	  BOOL bSuccess = Shell_NotifyIcon(NIM_MODIFY, &m_tnd);
598	
599	  // Zero out the balloon text string so that later operations won't redisplay
600	  // the balloon.
601	  m_tnd.szInfo[0] = _T('\0');
602	
603	  return bSuccess;
604	#endif
605	}
