882	void CSystemTray::InstallIconPending() {
883	  // Is the icon display pending, and it's not been set as "hidden"?
884	  if (!m_bShowIconPending || m_bHidden)
885	    return;
886	
887	  // Reset the flags to what was used at creation
888	  m_tnd.uFlags = m_uCreationFlags;
889	
890	  // Try and recreate the icon
891	  m_bHidden = !Shell_NotifyIcon(NIM_ADD, &m_tnd);
892	
893	  // If it's STILL hidden, then have another go next time...
894	  m_bShowIconPending = !m_bHidden;
895	
896	  ASSERT(m_bHidden == FALSE);
897	}
