900	// For minimising/maximising from system tray
901	
902	BOOL CALLBACK FindTrayWnd(HWND hwnd, LPARAM lParam) {
903	  TCHAR szClassName[256];
904	  GetClassName(hwnd, szClassName, 255);
905	
906	  // Did we find the Main System Tray? If so, then get its size and keep going
907	  if (_tcscmp(szClassName, _T("TrayNotifyWnd")) == 0) {
908	    LPRECT lpRect = (LPRECT)lParam;
909	    ::GetWindowRect(hwnd, lpRect);
910	    return TRUE;
911	  }
912	
913	  // Did we find the System Clock? If so, then adjust the size of the rectangle
914	  // we have and quit (clock will be found after the system tray)
915	  if (_tcscmp(szClassName, _T("TrayClockWClass")) == 0) {
916	    LPRECT lpRect = (LPRECT)lParam;
917	    RECT rectClock;
918	    ::GetWindowRect(hwnd, &rectClock);
919	    // if clock is above system tray adjust accordingly
920	    if (rectClock.bottom < lpRect->bottom - 5)  // 10 = random fudge factor.
921	      lpRect->top = rectClock.bottom;
922	    else
923	      lpRect->right = rectClock.left;
924	    return FALSE;
925	  }
926	
927	  return TRUE;
928	}
