930	#ifndef _WIN32_WCE
931	void CSystemTray::GetTrayWndRect(LPRECT lprect) {
932	#define DEFAULT_RECT_WIDTH 150
933	#define DEFAULT_RECT_HEIGHT 30
934	
935	  HWND hShellTrayWnd = FindWindow(_T("Shell_TrayWnd"), NULL);
936	  if (hShellTrayWnd) {
937	    GetWindowRect(hShellTrayWnd, lprect);
938	    EnumChildWindows(hShellTrayWnd, FindTrayWnd, (LPARAM)lprect);
939	    return;
940	  }
941	  // OK, we failed to get the rect from the quick hack. Either explorer isn't
942	  // running or it's a new version of the shell with the window class names
943	  // changed (how dare Microsoft change these undocumented class names!) So, we
944	  // try to find out what side of the screen the taskbar is connected to. We
945	  // know that the system tray is either on the right or the bottom of the
946	  // taskbar, so we can make a good guess at where to minimize to
947	  APPBARDATA appBarData;
948	  appBarData.cbSize = sizeof(appBarData);
949	  if (SHAppBarMessage(ABM_GETTASKBARPOS, &appBarData)) {
950	    // We know the edge the taskbar is connected to, so guess the rect of the
951	    // system tray. Use various fudge factor to make it look good
952	    switch (appBarData.uEdge) {
953	      case ABE_LEFT:
954	      case ABE_RIGHT:
955	        // We want to minimize to the bottom of the taskbar
956	        lprect->top = appBarData.rc.bottom - 100;
957	        lprect->bottom = appBarData.rc.bottom - 16;
958	        lprect->left = appBarData.rc.left;
959	        lprect->right = appBarData.rc.right;
960	        break;
961	
962	      case ABE_TOP:
963	      case ABE_BOTTOM:
964	        // We want to minimize to the right of the taskbar
965	        lprect->top = appBarData.rc.top;
966	        lprect->bottom = appBarData.rc.bottom;
967	        lprect->left = appBarData.rc.right - 100;
968	        lprect->right = appBarData.rc.right - 16;
969	        break;
970	    }
971	    return;
972	  }
973	
974	  // Blimey, we really aren't in luck. It's possible that a third party shell
975	  // is running instead of explorer. This shell might provide support for the
976	  // system tray, by providing a Shell_TrayWnd window (which receives the
977	  // messages for the icons) So, look for a Shell_TrayWnd window and work out
978	  // the rect from that. Remember that explorer's taskbar is the Shell_TrayWnd,
979	  // and stretches either the width or the height of the screen. We can't rely
980	  // on the 3rd party shell's Shell_TrayWnd doing the same, in fact, we can't
981	  // rely on it being any size. The best we can do is just blindly use the
982	  // window rect, perhaps limiting the width and height to, say 150 square.
983	  // Note that if the 3rd party shell supports the same configuraion as
984	  // explorer (the icons hosted in NotifyTrayWnd, which is a child window of
985	  // Shell_TrayWnd), we would already have caught it above
986	  if (hShellTrayWnd) {
987	    ::GetWindowRect(hShellTrayWnd, lprect);
988	    if (lprect->right - lprect->left > DEFAULT_RECT_WIDTH)
989	      lprect->left = lprect->right - DEFAULT_RECT_WIDTH;
990	    if (lprect->bottom - lprect->top > DEFAULT_RECT_HEIGHT)
991	      lprect->top = lprect->bottom - DEFAULT_RECT_HEIGHT;
992	
993	    return;
994	  }
995	
996	  // OK. Haven't found a thing. Provide a default rect based on the current work
997	  // area
998	  SystemParametersInfo(SPI_GETWORKAREA, 0, lprect, 0);
999	  lprect->left = lprect->right - DEFAULT_RECT_WIDTH;
1000	  lprect->top = lprect->bottom - DEFAULT_RECT_HEIGHT;
1001	}
