1007	
1008	  ai.cbSize = sizeof(ai);
1009	  SystemParametersInfo(SPI_GETANIMATION, sizeof(ai), &ai, 0);
1010	
1011	  return ai.iMinAnimate ? TRUE : FALSE;
1012	}
