1015	BOOL CSystemTray::RemoveTaskbarIcon(HWND hWnd) {
1016	  // Create static invisible window
1017	  if (!::IsWindow(m_hWndInvisible)) {
1018	    // 2007-11-14 GONG
1019	    m_hWndInvisible = CreateWindowEx(
1020	        0, _T("Static"), _T(""), WS_POPUP, CW_USEDEFAULT, CW_USEDEFAULT,
1021	        CW_USEDEFAULT, CW_USEDEFAULT, NULL, 0, NULL, 0);
1022	
1023	    if (!m_hWndInvisible)
1024	      return FALSE;
1025	  }
1026	
1027	  SetParent(hWnd, m_hWndInvisible);
1028	
1029	  return TRUE;
