1032	void CSystemTray::MinimiseToTray(HWND hWnd) {
1033	#ifndef _WIN32_WCE
1034	  if (GetDoWndAnimation()) {
1035	    RECT rectFrom, rectTo;
1036	
1037	    GetWindowRect(hWnd, &rectFrom);
1038	    GetTrayWndRect(&rectTo);
1039	
1040	    DrawAnimatedRects(hWnd, IDANI_CAPTION, &rectFrom, &rectTo);
1041	  }
1042	
1043	  RemoveTaskbarIcon(hWnd);
1044	  SetWindowLong(hWnd, GWL_STYLE, GetWindowLong(hWnd, GWL_STYLE) & ~WS_VISIBLE);
1045	#endif
1046	}
1047	
1048	void CSystemTray::MaximiseFromTray(HWND hWnd) {
1049	#ifndef _WIN32_WCE
1050	  if (GetDoWndAnimation()) {
1051	    RECT rectTo;
1052	    ::GetWindowRect(hWnd, &rectTo);
1053	
1054	    RECT rectFrom;
1055	    GetTrayWndRect(&rectFrom);
1056	
1057	    ::SetParent(hWnd, NULL);
1058	    DrawAnimatedRects(hWnd, IDANI_CAPTION, &rectFrom, &rectTo);
1059	  } else
1060	    ::SetParent(hWnd, NULL);
1061	
1062	  SetWindowLong(hWnd, GWL_STYLE, GetWindowLong(hWnd, GWL_STYLE) | WS_VISIBLE);
1063	  RedrawWindow(
1064	      hWnd, NULL, NULL,
1065	      RDW_UPDATENOW | RDW_ALLCHILDREN | RDW_FRAME | RDW_INVALIDATE | RDW_ERASE);
1066	
1067	  // Move focus away and back again to ensure taskbar icon is recreated
1068	  if (::IsWindow(m_hWndInvisible))
1069	    SetActiveWindow(m_hWndInvisible);
1070	  SetActiveWindow(hWnd);
1071	  SetForegroundWindow(hWnd);
1072	#endif
1073	}
