  // 2007-11-14 GONG
  // #ifdef _UNICODE
  //    strBuffer[0] = _T('\0');
  //    MultiByteToWideChar(CP_ACP, 0, m_tnd.szTip, -1, strBuffer,
  //    m_nMaxTooltipLength, NULL, NULL);
  // #else
