253	DWORD ServerImpl::OnUpdateInputPosition(WEASEL_IPC_COMMAND uMsg,
254	                                        DWORD wParam,
255	                                        DWORD lParam) {
256	  if (!m_pRequestHandler)
257	    return 0;
258	  /*
259	   * 移位标志 = 1bit == 0
260	   * height: 0~127 = 7bit
261	   * top:-2048~2047 = 12bit（有符号）
262	   * left:-2048~2047 = 12bit（有符号）
263	   *
264	   * 高解析度下：
265	   * 移位标志 = 1bit == 1
266	   * height: 0~254 = 7bit（舍弃低1位）
267	   * top: -4096~4094 = 12bit（有符号，舍弃低1位）
268	   * left: -4096~4094 = 12bit（有符号，舍弃低1位）
269	   */
270	  RECT rc;
271	  int hi_res = (wParam >> 31) & 0x01;
272	  rc.left = ((wParam & 0x7ff) - (wParam & 0x800)) << hi_res;
273	  rc.top = (((wParam >> 12) & 0x7ff) - ((wParam >> 12) & 0x800)) << hi_res;
274	  const int width = 6;
275	  int height = ((wParam >> 24) & 0x7f) << hi_res;
276	  rc.right = rc.left + width;
277	  rc.bottom = rc.top + height;
278	
279	  {
280	    using PPTLPFPMDPI = BOOL(WINAPI*)(HWND, LPPOINT);
281	    PPTLPFPMDPI PhysicalToLogicalPointForPerMonitorDPI =
282	        (PPTLPFPMDPI)::GetProcAddress(m_hUser32Module,
283	                                      "PhysicalToLogicalPointForPerMonitorDPI");
284	    POINT lt = {rc.left, rc.top};
285	    POINT rb = {rc.right, rc.bottom};
286	    PhysicalToLogicalPointForPerMonitorDPI(NULL, &lt);
287	    PhysicalToLogicalPointForPerMonitorDPI(NULL, &rb);
288	    rc = {lt.x, lt.y, rb.x, rb.y};
289	  }
290	
291	  m_pRequestHandler->UpdateInputPosition(rc, lParam);
292	  return 0;
293	}
